mod history; pub struct Buffer { pub lines: Vec<String>, pub path: Option<String>, pub history: history::History, } impl Buffer { pub fn new() -> Self { Self { lines: vec![String::new()], path: None, history: history::History::new() } } pub fn insert_line(&mut self, row: usize, col: usize, text: &str) { if row < self.lines.len() { self.lines[row].insert_str(col, text); self.history.undo_stack.push(history::Command::Insert { row, col, text: text.to_string() }); } } pub fn undo(&mut self) { if let Some(cmd) = self.history.undo_stack.pop() { match cmd { history::Command::Insert { row, col, text } => { if row < self.lines.len() { let end = col + text.len(); self.lines[row].replace_range(col..end, ""); } self.history.redo_stack.push(cmd); } history::Command::Delete { .. } => { /* Lógica de rehacer borrado pendiente */ } } } } pub fn get_text(&self) -> String { self.lines.join("\n") } }
